UPDATE decision_nodes SET data = '{"type":"info","module":3,"title":"Emergent Workup — Acute Neuropathy","body":"**Emergent Evaluation for Acute Neuropathy:**\n\n**Bedside Respiratory Assessment:**\n• **FVC** (Forced Vital Capacity) — most useful\n  - <20 mL/kg or <1 L = high intubation risk\n  - Decline >30% from baseline = concerning\n• **NIF** (Negative Inspiratory Force)\n  - Worse than −30 cmH2O = impending failure\n• Check q4h if GBS suspected\n\n**Lumbar Puncture:**\n• **Classic GBS finding:** Albuminocytologic dissociation\n  - Elevated protein (>45 mg/dL)\n  - Normal cell count (<10 cells)\n• May be normal in first week\n• Also rules out infectious/malignant meningitis\n\n**Labs:**\n• Standard workup PLUS:\n• Anti-ganglioside antibodies (GM1, GD1a, GQ1b)\n• Consider stool for botulinum toxin\n• Lyme serologies in endemic areas\n\n**Imaging:**\n• MRI spine if cord compression suspected\n• CXR (aspiration risk, pulmonary function)\n\n**Consults:**\n• Neurology — emergent\n• ICU if respiratory compromise [2][3][6]","citation":[2,3,6],"next":"pn-gbs-pathway","calculatorLinks":[{"id":"gbs-fvc-nif","label":"FVC/NIF Calculator"},{"id":"gbs-lp-interp","label":"LP Interpreter"},{"id":"gbs-intubation","label":"Intubation Decision"}],"safetyLevel":"critical"}'::jsonb
WHERE id = 'pn-emergent-workup' AND tree_id = 'peripheral-neuropathy';

