UPDATE decision_nodes SET data = '{"type":"question","module":4,"title":"GBS vs Mimics — Critical Differentiation","body":"**Guillain-Barré Syndrome Features:**\n• Acute ascending weakness (<4 weeks to nadir)\n• Areflexia or hyporeflexia\n• Symmetric involvement\n• Recent infection (Campylobacter, CMV, EBV)\n• Autonomic instability (HR, BP fluctuations)\n\n**Key GBS Mimics to Exclude:**\n\n| Mimic | Distinguishing Features |\n|-------|-------------------------|\n| **Transverse myelitis** | Sensory level, sphincter early |\n| **Cord compression** | Back pain, sensory level, MRI+ |\n| **Botulism** | Descending, pupil involvement |\n| **Tick paralysis** | Look for tick, rapid reversal |\n| **Hypokalemia** | Check K+, resolves with repletion |\n| **Porphyria** | Abdominal pain, psychiatric, urine |\n| **Myasthenia gravis** | Fatigable, ocular, no sensory |\n| **Critical illness poly** | ICU setting, sepsis history |\n\n**Does this fit GBS criteria?** [2][6]","citation":[2,6],"options":[{"label":"Likely GBS","description":"Ascending, areflexic, symmetric","next":"pn-gbs-management","urgency":"critical"},{"label":"Mimic suspected","description":"Features don''t fit GBS","next":"pn-mimic-workup"},{"label":"Uncertain","description":"Need more evaluation","next":"pn-emergent-workup"}],"calculatorLinks":[{"id":"gbs-egris","label":"EGRIS Score"},{"id":"bot-ddx","label":"Botulism DDx"},{"id":"mg-ice-test","label":"Ice Test (MG)"}]}'::jsonb
