UPDATE decision_nodes SET data = '{"type":"result","module":4,"title":"GBS — ED Management","body":"**Suspected GBS — Immediate Actions:**\n\n**1. Airway/Respiratory Monitoring:**\n• Serial FVC and NIF q4h minimum\n• Intubation thresholds:\n  - FVC <20 mL/kg or <1 L\n  - NIF worse than −30 cmH2O\n  - Rapid decline (>30% in hours)\n  - Bulbar dysfunction with aspiration risk\n• Early intubation preferred — RSI okay\n\n**2. Autonomic Monitoring:**\n• Continuous cardiac monitoring\n• Watch for HR/BP lability\n• Avoid medications that worsen dysautonomia\n\n**3. Definitive Treatment (neurology-directed):**\n• **IVIG** 0.4 g/kg/day × 5 days, OR\n• **Plasmapheresis** (PLEX) 5 exchanges over 1-2 weeks\n• Equally effective — IVIG more practical in most settings\n• Steroids NOT effective in GBS\n\n**4. Supportive Care:**\n• DVT prophylaxis\n• Pain management (neuropathic pain common)\n• PT/OT early\n\n**Disposition:** ICU admission for respiratory monitoring.\n\n➡️ For detailed GBS management: [GBS Consult](#/tree/guillain-barre) [2][3][6]","citation":[2,3,6],"recommendation":"Admit to ICU. Serial respiratory monitoring (FVC/NIF q4h). Neurology consult for IVIG or plasmapheresis. Continuous cardiac monitoring for autonomic instability.","calculatorLinks":[{"id":"gbs-ivig-plex","label":"IVIG vs PLEX"},{"id":"gbs-fvc-nif","label":"FVC/NIF"},{"id":"gbs-intubation","label":"Intubation Decision"}],"safetyLevel":"critical"}'::jsonb
